import{c as s,Q as n,j as e,m as i}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"App 从代码到用户手机的全过程","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/02-App从代码到用户手机的全过程.md","filePath":"mobileCommonLearning/02-App从代码到用户手机的全过程.md","lastUpdated":1780912084000}'),p={name:"mobileCommonLearning/02-App从代码到用户手机的全过程.md"};function t(l,a,d,o,r,c){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="app-从代码到用户手机的全过程" tabindex="-1">App 从代码到用户手机的全过程 <a class="header-anchor" href="#app-从代码到用户手机的全过程" aria-label="Permalink to &quot;App 从代码到用户手机的全过程&quot;">​</a></h1><p>App 上线不是 <code>build</code> 一下就结束。真正的链路从代码开始,到用户设备完成安装和更新才算结束。</p><p>一句话先记住:<strong>移动端发布 = 编译、打包、签名、上传、审核、分发、安装、监控的一条生产链路。</strong></p><hr><h2 id="一、完整链路" tabindex="-1">一、完整链路 <a class="header-anchor" href="#一、完整链路" aria-label="Permalink to &quot;一、完整链路&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源码</span></span>
<span class="line"><span>  -&gt; 依赖恢复</span></span>
<span class="line"><span>  -&gt; 编译</span></span>
<span class="line"><span>  -&gt; 资源处理</span></span>
<span class="line"><span>  -&gt; 打包</span></span>
<span class="line"><span>  -&gt; 签名</span></span>
<span class="line"><span>  -&gt; 符号表 / mapping 归档</span></span>
<span class="line"><span>  -&gt; 上传商店 / 渠道</span></span>
<span class="line"><span>  -&gt; 审核</span></span>
<span class="line"><span>  -&gt; 灰度 / 分阶段发布</span></span>
<span class="line"><span>  -&gt; 用户下载</span></span>
<span class="line"><span>  -&gt; 安装 / 覆盖更新</span></span>
<span class="line"><span>  -&gt; 崩溃和性能监控</span></span></code></pre></div><p>每一步都可能独立出事故。</p><hr><h2 id="二、android-这条链" tabindex="-1">二、Android 这条链 <a class="header-anchor" href="#二、android-这条链" aria-label="Permalink to &quot;二、Android 这条链&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kotlin / Java / Dart</span></span>
<span class="line"><span>  -&gt; class / dex</span></span>
<span class="line"><span>  -&gt; resource table</span></span>
<span class="line"><span>  -&gt; manifest merge</span></span>
<span class="line"><span>  -&gt; APK / AAB</span></span>
<span class="line"><span>  -&gt; signing</span></span>
<span class="line"><span>  -&gt; zipalign / optimize</span></span>
<span class="line"><span>  -&gt; Play / 国内渠道 / 官网</span></span></code></pre></div><p>Android 的核心约束:</p><ul><li><code>applicationId</code> 决定应用身份</li><li>release 签名决定能不能覆盖更新</li><li><code>versionCode</code> 必须递增</li><li>target SDK 会被商店政策约束</li><li>多渠道分发会放大签名和版本管理复杂度</li></ul><hr><h2 id="三、ios-这条链" tabindex="-1">三、iOS 这条链 <a class="header-anchor" href="#三、ios-这条链" aria-label="Permalink to &quot;三、iOS 这条链&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swift / Objective-C / Dart</span></span>
<span class="line"><span>  -&gt; Mach-O binary</span></span>
<span class="line"><span>  -&gt; .app bundle</span></span>
<span class="line"><span>  -&gt; entitlements</span></span>
<span class="line"><span>  -&gt; code signing</span></span>
<span class="line"><span>  -&gt; .xcarchive</span></span>
<span class="line"><span>  -&gt; IPA / App Store upload</span></span>
<span class="line"><span>  -&gt; TestFlight / App Store</span></span></code></pre></div><p>iOS 的核心约束:</p><ul><li>Bundle ID 决定应用身份</li><li>Team ID 决定归属</li><li>certificate + private key 决定本机能不能签</li><li>Provisioning Profile 决定能签哪个 App、用哪些能力、发到哪里</li><li>build number 必须递增</li></ul><hr><h2 id="四、debug、profile、release" tabindex="-1">四、Debug、Profile、Release <a class="header-anchor" href="#四、debug、profile、release" aria-label="Permalink to &quot;四、Debug、Profile、Release&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>用途</th><th>特点</th></tr></thead><tbody><tr><td>Debug</td><td>开发调试</td><td>慢、体积大、有调试能力</td></tr><tr><td>Profile</td><td>性能测试</td><td>接近 release,保留 profiling 能力</td></tr><tr><td>Release</td><td>发布</td><td>优化、混淆、签名、体积最小</td></tr></tbody></table><p>发布前必须测 release。很多问题只在 release 出现:</p><ul><li>R8 / ProGuard 混淆导致反射崩溃</li><li>资源压缩误删</li><li>iOS entitlements 不匹配</li><li>release 签名下三方 SDK 校验失败</li><li>debug 环境变量没切到 production</li></ul><hr><h2 id="五、符号表和-mapping" tabindex="-1">五、符号表和 mapping <a class="header-anchor" href="#五、符号表和-mapping" aria-label="Permalink to &quot;五、符号表和 mapping&quot;">​</a></h2><p>发布产物要配套保存:</p><table tabindex="0"><thead><tr><th>平台</th><th>文件</th><th>用途</th></tr></thead><tbody><tr><td>Android</td><td>mapping.txt</td><td>混淆后还原 Java / Kotlin 堆栈</td></tr><tr><td>Android</td><td>native symbols</td><td>还原 NDK / so 崩溃</td></tr><tr><td>iOS</td><td>dSYM</td><td>还原 crash 堆栈</td></tr><tr><td>Flutter</td><td>split debug info</td><td>还原 Dart 堆栈</td></tr></tbody></table><p>没有这些文件,线上崩溃只能看到乱码堆栈。</p><p>发布流程里要把它们上传到 Sentry、Firebase Crashlytics、Bugly 或内部平台。</p><hr><h2 id="六、商店和渠道不是同一回事" tabindex="-1">六、商店和渠道不是同一回事 <a class="header-anchor" href="#六、商店和渠道不是同一回事" aria-label="Permalink to &quot;六、商店和渠道不是同一回事&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App Store       iOS 主分发入口</span></span>
<span class="line"><span>TestFlight      iOS 内测入口</span></span>
<span class="line"><span>Google Play     Android 国际主渠道</span></span>
<span class="line"><span>国内应用市场     华为 / 小米 / OPPO / vivo / 荣耀 / 应用宝等</span></span>
<span class="line"><span>官网 APK         自有分发</span></span>
<span class="line"><span>企业分发         公司内部分发</span></span></code></pre></div><p>渠道越多,越需要统一:</p><ul><li>版本号规则</li><li>签名资产</li><li>渠道包生成</li><li>上架材料</li><li>回滚和下架流程</li><li>渠道后台账号权限</li></ul><hr><h2 id="七、安装和覆盖更新" tabindex="-1">七、安装和覆盖更新 <a class="header-anchor" href="#七、安装和覆盖更新" aria-label="Permalink to &quot;七、安装和覆盖更新&quot;">​</a></h2><p>覆盖更新需要同时满足:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>同一个应用身份</span></span>
<span class="line"><span>签名兼容</span></span>
<span class="line"><span>版本号更高</span></span>
<span class="line"><span>安装来源允许</span></span></code></pre></div><p>Android:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>applicationId 相同 + 签名兼容 + versionCode 更高</span></span></code></pre></div><p>iOS:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bundle ID 相同 + 同一 App 记录 + build 更高</span></span></code></pre></div><p>不要以为&quot;文件名一样&quot;就是同一个 App。移动端认的是包身份和签名。</p><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><p>典型事故:</p><ol><li>debug 包测完直接发版,release 包崩溃。</li><li>Android keystore 换了,老用户无法覆盖升级。</li><li>iOS profile 没包含 Push / Associated Domains,线上能力失效。</li><li>versionCode / build number 没递增,商店拒收。</li><li>mapping / dSYM 没上传,线上 crash 无法定位。</li><li>国内渠道包混用,用户装到了错误渠道版本。</li><li>CI 和本地打包环境不一致,同一 commit 产物不同。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] 是否明确 debug / profile / release 用途</li><li>[ ] release 包是否真机跑过核心流程</li><li>[ ] Android applicationId 是否最终确定</li><li>[ ] iOS Bundle ID 是否最终确定</li><li>[ ] versionCode / build number 是否递增</li><li>[ ] release 签名材料是否可恢复</li><li>[ ] mapping / dSYM / native symbols 是否归档</li><li>[ ] 商店和渠道账号是否明确负责人</li><li>[ ] 上架后是否能看到 crash 和性能数据</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>代码只是输入</span></span>
<span class="line"><span>签名决定身份</span></span>
<span class="line"><span>商店决定分发</span></span>
<span class="line"><span>版本号决定升级</span></span>
<span class="line"><span>符号表决定排障</span></span>
<span class="line"><span>监控决定上线后能不能维护</span></span></code></pre></div><p>下一篇 03 讲包名、Bundle ID、版本号与构建号。</p>`,53)])])}const u=s(p,[["render",t]]);export{g as __pageData,u as default};
